func featureFieldValue(f *feature.Feature, field string) string {
	if f == nil {
		return ""
	}
	switch field {
	case "key":
		return f.Key
	case "name":
		return f.Name
	case "description":
		return f.Description
	case "type":
		return string(f.Type)
	case "status":
		return string(f.Status)
	case "period":
		return string(f.Period)
	case "default_limit":
		if f.DefaultLimit != 0 {
			return strconv.FormatInt(f.DefaultLimit, 10)
		}
		return ""
	case "app_id":
		return f.AppID
	default:
		return ""
	}
}

